defmodule BinaryTreeTest do
  use ExUnit.Case, async: true

  test "empty tree is a binary search tree" do
    assert BinaryTree.binary_search_tree?(nil) == true
  end

  test "single node tree is a binary search tree" do
    tree = %{val: 5, left: nil, right: nil}
    assert BinaryTree.binary_search_tree?(tree) == true
  end

  test "simple binary search tree" do
    tree = %{
      val: 5,
      left: %{
        val: 3,
        left: %{val: 2, left: nil, right: nil},
        right: %{val: 4, left: nil, right: nil}
      },
      right: %{val: 7, left: nil, right: nil}
    }

    assert BinaryTree.binary_search_tree?(tree) == true
  end

  test "binary tree that is not a binary search tree" do
    tree = %{
      val: 5,
      left: %{
        val: 3,
        left: %{val: 1, left: nil, right: nil},
        right: %{val: 4, left: nil, right: nil}
      },
      right: %{val: 2, left: nil, right: nil}
    }

    assert BinaryTree.binary_search_tree?(tree) == false
  end

  test "more complex binary search tree" do
    tree = %{
      val: 10,
      left: %{
        val: 5,
        left: %{val: 3, left: nil, right: nil},
        right: %{val: 7, left: nil, right: nil}
      },
      right: %{
        val: 15,
        left: %{val: 12, left: nil, right: nil},
        right: %{val: 17, left: nil, right: nil}
      }
    }

    assert BinaryTree.binary_search_tree?(tree) == true
  end

  test "tree with duplicate values is not a binary search tree" do
    tree = %{
      val: 5,
      left: %{val: 5, left: nil, right: nil},
      right: nil
    }

    assert BinaryTree.binary_search_tree?(tree) == false
  end
